{"command": "cd /data/zrwang/auto-opt/utils/llvm-85265 && cat <<'CODEEOF' > /tmp/fptrunc_opt.cpp

  // fcmp (fptrunc X), C -> fcmp X, threshold
  // The threshold depends on the predicate:
  // - OGE/UGE: X >= threshold where threshold = midpoint(C, prev(C))
  // - OGT/UGT: X > threshold where threshold = midpoint(C, next(C))
  // - OLE/ULE: X <= threshold where threshold = midpoint(C, next(C))  
  // - OLT/ULT: X < threshold where threshold = midpoint(C, prev(C))
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      Type *SrcTy = X->getType()->getScalarType();
      Type *DstTy = Op0->getType()->getScalarType();
      // Only handle cases where we're truncating to a smaller type
      if (SrcTy->getFPMantissaWidth() > DstTy->getFPMantissaWidth()) {
        const fltSemantics &SrcSem = SrcTy->getFltSemantics();
        const fltSemantics &DstSem = DstTy->getFltSemantics();
        APFloat CFloat = *C;
        bool Ignored;
        CFloat.convert(DstSem, APFloat::rmNearestTiesToEven, &Ignored);

        // Determine which midpoint to use based on predicate
        bool UseNext = false; // true for midpoint(C, next(C)), false for midpoint(C, prev(C))
        bool ValidPredicate = false;

        switch (Pred) {
        case FCmpInst::FCMP_OLE:
        case FCmpInst::FCMP_ULE:
          // X <= threshold, threshold = midpoint(C, next(C))
          UseNext = true;
          ValidPredicate = true;
          break;
        case FCmpInst::FCMP_OGE:
        case FCmpInst::FCMP_UGE:
        case FCmpInst::FCMP_OLT:
        case FCmpInst::FCMP_ULT:
          // X >= or X < threshold, threshold = midpoint(C, prev(C))
          UseNext = false;
          ValidPredicate = true;
          break;
        case FCmpInst::FCMP_OGT:
        case FCmpInst::FCMP_UGT:
          // X > threshold, threshold = midpoint(C, next(C))
          UseNext = true;
          ValidPredicate = true;
          break;
        default:
          // Other predicates (OEQ, ONE, UEQ, UNE, ORD, UNO) are more complex
          break;
        }

        if (!ValidPredicate)
          return nullptr;

        APFloat NeighborC = CFloat;
        APFloat::opStatus Status = UseNext ? NeighborC.next(false) : NeighborC.next(true);
        if (Status != APFloat::opOK)
          return nullptr;

        // Compute midpoint in destination type: (CFloat + NeighborC) / 2
        APFloat Threshold = CFloat;
        Status = Threshold.add(NeighborC, APFloat::rmNearestTiesToEven);
        if (Status != APFloat::opOK)
          return nullptr;
        APFloat Two(DstSem, 2);
        Status = Threshold.divide(Two, APFloat::rmNearestTiesToEven);
        if (Status != APFloat::opOK)
          return nullptr;

        // Convert threshold to source type
        Threshold.convert(SrcSem, APFloat::rmNearestTiesToEven, &Ignored);

        Constant *NewC = ConstantFP::get(X->getType(), Threshold);
        FCmpInst *Result = new FCmpInst(Pred, X, NewC, "", &I);
        Result->copyFastMathFlags(&I);
        return Result;
      }
    }
  }
